        this.v2 = new _paper.Path({segments:[new _paper.Point(0,0),new _paper.Point(0,0)],strokeScaling:false,strokeWidth:1,strokeColor:'white',dashArray:[6,6]});
        this.crosshairTool.addChildren([this.h1, this.h2, this.v1, this.v2]);
