function createPngDataTable() {
    /* Table of CRCs of all 8-bit messages. */
    const crcTable = new Int32Array(256);
    for (let n = 0; n < 256; n++) {
      let c = n;
      for (let k = 0; k < 8; k++) {
        c = (c & 1) ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
      }
      crcTable[n] = c;
    }
    return crcTable;
  }
  
  function calcCrc(buf) {
    let c = -1;
    if (!pngDataTable) pngDataTable = createPngDataTable();
    for (let n = 0; n < buf.length; n++) {
      c = pngDataTable[(c ^ buf[n]) & 0xFF] ^ (c >>> 8);
    }
    return c ^ -1;
  }
  
  let pngDataTable;
  
  const PNG = 'image/png';
  const JPEG = 'image/jpeg';
  
  // those are 3 possible signature of the physBlock in base64.
  // the pHYs signature block is preceed by the 4 bytes of lenght. The length of
  // the block is always 9 bytes. So a phys block has always this signature:
  // 0 0 0 9 p H Y s.
  // However the data64 encoding aligns we will always find one of those 3 strings.
  // this allow us to find this particular occurence of the pHYs block without
  // converting from b64 back to string
  const b64PhysSignature1 = 'AAlwSFlz';
  const b64PhysSignature2 = 'AAAJcEhZ';
  const b64PhysSignature3 = 'AAAACXBI';
  
  const _P = 'p'.charCodeAt(0);
  const _H = 'H'.charCodeAt(0);
  const _Y = 'Y'.charCodeAt(0);
  const _S = 's'.charCodeAt(0);
  
  function changeDpiBlob(blob, dpi) {
    // 33 bytes are ok for pngs and jpegs
    // to contain the information.
    const headerChunk = blob.slice(0, 33);
    return new Promise((resolve, reject) => {
      const fileReader = new FileReader();
      fileReader.onload = () => {
        const dataArray = new Uint8Array(fileReader.result);
        const tail = blob.slice(33);
        const changedArray = changeDpiOnArray(dataArray, dpi, blob.type);
        resolve(new Blob([changedArray, tail], { type: blob.type }));
      };
      fileReader.readAsArrayBuffer(headerChunk);
    });
  }
  
  function changeDpiDataUrl(base64Image, dpi) {
    const dataSplitted = base64Image.split(',');
    const format = dataSplitted[0];
    const body = dataSplitted[1];
    let type;
    let headerLength;
    let overwritepHYs = false;
    if (format.indexOf(PNG) !== -1) {
      type = PNG;
      const b64Index = detectPhysChunkFromDataUrl(body);
      // 28 bytes in dataUrl are 21bytes, length of phys chunk with everything inside.
      if (b64Index >= 0) {
        headerLength = Math.ceil((b64Index + 28) / 3) * 4;
        overwritepHYs = true;
      } else {
        headerLength = 33 / 3 * 4;
      }
    }
    if (format.indexOf(JPEG) !== -1) {
      type = JPEG;
      headerLength = 18 / 3 * 4;
    }
    // 33 bytes are ok for pngs and jpegs
    // to contain the information.
    const stringHeader = body.substring(0, headerLength);
    const restOfData = body.substring(headerLength);
    const headerBytes = atob(stringHeader);
    const dataArray = new Uint8Array(headerBytes.length);
    for (let i = 0; i < dataArray.length; i++) {
      dataArray[i] = headerBytes.charCodeAt(i);
    }
    const finalArray = changeDpiOnArray(dataArray, dpi, type, overwritepHYs);
    const base64Header = btoa(String.fromCharCode(...finalArray));
    return [format, ',', base64Header, restOfData].join('');
  }
  
  function detectPhysChunkFromDataUrl(data) {
    let b64index = data.indexOf(b64PhysSignature1);
    if (b64index === -1) {
      b64index = data.indexOf(b64PhysSignature2);
    }
    if (b64index === -1) {
      b64index = data.indexOf(b64PhysSignature3);
    }
    // if b64index === -1 chunk is not found
    return b64index;
  }
  
  function searchStartOfPhys(data) {
    const length = data.length - 1;
    // we check from the end since we cut the string in proximity of the header
    // the header is within 21 bytes from the end.
    for (let i = length; i >= 4; i--) {
      if (data[i - 4] === 9 && data[i - 3] === _P &&
        data[i - 2] === _H && data[i - 1] === _Y &&
        data[i] === _S) {
          return i - 3;
      }
    }
  }
  
  function changeDpiOnArray(dataArray, dpi, format, overwritepHYs) {
    if (format === JPEG) {
      dataArray[13] = 1; // 1 pixel per inch or 2 pixel per cm
      dataArray[14] = dpi >> 8; // dpiX high byte
      dataArray[15] = dpi & 0xff; // dpiX low byte
      dataArray[16] = dpi >> 8; // dpiY high byte
      dataArray[17] = dpi & 0xff; // dpiY low byte
      return dataArray;
    }
    if (format === PNG) {
      const physChunk = new Uint8Array(13);
      // chunk header pHYs
      // 9 bytes of data
      // 4 bytes of crc
      // this multiplication is because the standard is dpi per meter.
      dpi *= 39.3701;
      physChunk[0] = _P;
      physChunk[1] = _H;
      physChunk[2] = _Y;
      physChunk[3] = _S;
      physChunk[4] = dpi >>> 24; // dpiX highest byte
      physChunk[5] = dpi >>> 16; // dpiX veryhigh byte
      physChunk[6] = dpi >>> 8; // dpiX high byte
      physChunk[7] = dpi & 0xff; // dpiX low byte
      physChunk[8] = physChunk[4]; // dpiY highest byte
      physChunk[9] = physChunk[5]; // dpiY veryhigh byte
      physChunk[10] = physChunk[6]; // dpiY high byte
      physChunk[11] = physChunk[7]; // dpiY low byte
      physChunk[12] = 1; // dot per meter....
  
      const crc = calcCrc(physChunk);
  
      const crcChunk = new Uint8Array(4);
      crcChunk[0] = crc >>> 24;
      crcChunk[1] = crc >>> 16;
      crcChunk[2] = crc >>> 8;
      crcChunk[3] = crc & 0xff;
  
      if (overwritepHYs) {
        const startingIndex = searchStartOfPhys(dataArray);
        dataArray.set(physChunk, startingIndex);
        dataArray.set(crcChunk, startingIndex + 13);
        return dataArray;
      } else {
        // i need to give back an array of data that is divisible by 3 so that
        // dataurl encoding gives me integers, for luck this chunk is 17 + 4 = 21
        // if it was we could add a text chunk contaning some info, untill desired
        // length is met.
  
        // chunk structur 4 bytes for length is 9
        const chunkLength = new Uint8Array(4);
        chunkLength[0] = 0;
        chunkLength[1] = 0;
        chunkLength[2] = 0;
        chunkLength[3] = 9;
  
        const finalHeader = new Uint8Array(54);
        finalHeader.set(dataArray, 0);
        finalHeader.set(chunkLength, 33);
        finalHeader.set(physChunk, 37);
        finalHeader.set(crcChunk, 50);
        return finalHeader;
      }
    }
  }
  
;// ./src/js/overlays/screenshot/screenshot-settings.mjs
const STORAGE_KEY = 'osd-paperjs-annotation.screenshotOverlay.v1';

function clampNumber(v, { min = -Infinity, max = Infinity, fallback = 0 } = {}) {
    const n = Number(v);
    if (!Number.isFinite(n)) return fallback;
    if (n < min) return min;
    if (n > max) return max;
    return n;
}

function defaultScreenshotSettings() {
    return {
        mode: 'free', // 'free' | 'fixed'
        output: {
            mode: 'preset', // 'preset' | 'other'
            presetFactor: 1,
            otherFactor: 1,
        },
        free: {
            aspectLocked: false,
            aspectWidth: 1,
            aspectHeight: 1,
        },
        fixed: {
            baseWidthPx: 256,
            baseHeightPx: 256,
            autoCreateOnClick: true,
        },
    };
}

function loadScreenshotSettings() {
    const defaults = defaultScreenshotSettings();
    try {
        const raw = window.localStorage.getItem(STORAGE_KEY);
        if (!raw) return defaults;
        const parsed = JSON.parse(raw);
        return normalizeScreenshotSettings(parsed, defaults);
    } catch {
        return defaults;
    }
}

function saveScreenshotSettings(settings) {
    try {
        const normalized = normalizeScreenshotSettings(settings, defaultScreenshotSettings());
        window.localStorage.setItem(STORAGE_KEY, JSON.stringify(normalized));
    } catch {
        // ignore storage errors (private mode, quota, etc.)
    }
}

function normalizeScreenshotSettings(input, defaults = defaultScreenshotSettings()) {
    const s = input && typeof input === 'object' ? input : {};
    const mode = s.mode === 'fixed' ? 'fixed' : 'free';

    const free = s.free && typeof s.free === 'object' ? s.free : {};
    const fixed = s.fixed && typeof s.fixed === 'object' ? s.fixed : {};
    const outputIn = s.output && typeof s.output === 'object' ? s.output : {};

    const aspectWidth = clampNumber(free.aspectWidth ?? defaults.free.aspectWidth, { min: 0.001, max: 1e9, fallback: defaults.free.aspectWidth });
    const aspectHeight = clampNumber(free.aspectHeight ?? defaults.free.aspectHeight, { min: 0.001, max: 1e9, fallback: defaults.free.aspectHeight });

    const baseWidthPx = Math.round(clampNumber(fixed.baseWidthPx ?? defaults.fixed.baseWidthPx, { min: 1, max: 1e7, fallback: defaults.fixed.baseWidthPx }));
    const baseHeightPx = Math.round(clampNumber(fixed.baseHeightPx ?? defaults.fixed.baseHeightPx, { min: 1, max: 1e7, fallback: defaults.fixed.baseHeightPx }));
    const autoCreateOnClick = fixed.autoCreateOnClick == null ? defaults.fixed.autoCreateOnClick : Boolean(fixed.autoCreateOnClick);

    // Migrate older settings that stored fixed.downsampleFactor on the fixed object.
    const legacyFactor = fixed.downsampleFactor;

    let outputMode = outputIn.mode === 'other' ? 'other' : 'preset';
    let presetFactor = clampNumber(
        outputIn.presetFactor ?? legacyFactor ?? defaults.output.presetFactor,
        { min: 0.000001, max: 1e9, fallback: defaults.output.presetFactor }
    );
    // If legacy factor wasn't a clean power-of-two, treat it as "other".
    if (legacyFactor != null && outputIn.mode == null && outputIn.presetFactor == null) {
        const isPow2 = Number.isFinite(legacyFactor) && legacyFactor > 0 && Math.log2(legacyFactor) % 1 === 0;
        if (!isPow2) {
            outputMode = 'other';
        }
    }

    const otherFactor = clampNumber(
        outputIn.otherFactor ?? (outputMode === 'other' ? legacyFactor : defaults.output.otherFactor),
        { min: 0.000001, max: 1e9, fallback: defaults.output.otherFactor }
    );

    return {
        mode,
        output: {
            mode: outputMode,
            presetFactor,
            otherFactor,
        },
        free: {
            aspectLocked: Boolean(free.aspectLocked),
            aspectWidth,
            aspectHeight,
        },
        fixed: {
            baseWidthPx,
            baseHeightPx,
            autoCreateOnClick,
        },
    };
}


;// ./src/js/overlays/screenshot/screenshot-sizing.mjs
/**
 * Shared helpers for screenshot output sizing from a base (full-res) region size.
 */

function computeOutputSize(baseW, baseH, factor) {
    const f = Number(factor);
    const bw = Number(baseW);
    const bh = Number(baseH);
    if (!Number.isFinite(f) || f <= 0) return { outW: 1, outH: 1 };
    const outW = Math.max(1, Math.round(bw / f));
    const outH = Math.max(1, Math.round(bh / f));
    return { outW, outH };
}

/**
 * Build preset power-of-two downsample options plus an "Other..." sentinel.
 */
function buildDownsampleOptions({
    baseW,
    baseH,
    maxDim = 23767,
    maxArea = 268435456,
    factors = [1, 2, 4, 8, 16, 32],
} = {}) {
    const bw = Number(baseW);
    const bh = Number(baseH);
    const opts = [];

    factors.forEach((f) => {
        const factor = Number(f);
        if (!Number.isFinite(factor) || factor <= 0) return;
        const { outW, outH } = computeOutputSize(bw, bh, factor);
        let disabledReason = null;
        if (outW < 1 || outH < 1) disabledReason = 'Too small';
        else if (outW > maxDim || outH > maxDim) disabledReason = 'Exceeds maximum dimension';
        else if (outW * outH > maxArea) disabledReason = 'Exceeds maximum area';
        const disabled = disabledReason != null;
        opts.push({
            kind: 'factor',
            factor,
            outW,
            outH,
            disabled,
            disabledReason,
            label: `${outW} × ${outH} (${formatFractionLabel(factor)})`,
        });
    });

    opts.push({ kind: 'other' });
    return opts;
}

function formatFractionLabel(factor) {
    const f = Number(factor);
    if (!Number.isFinite(f) || f <= 0) return '';
    if (f === 1) return '1/1';
    // Prefer clean integers (2,4,8...) as 1/N
    if (Number.isInteger(f)) return `1/${f}`;
    return `d=${f}`;
}

