const fieldofview_settings_STORAGE_KEY = 'osd-paperjs-annotation.fieldOfViewOverlay.v1';

function fieldofview_settings_clampNumber(v, { min = -Infinity, max = Infinity, fallback = 0 } = {}) {
    const n = Number(v);
    if (!Number.isFinite(n)) return fallback;
    if (n < min) return min;
    if (n > max) return max;
    return n;
}

function defaultFieldOfViewSettings() {
    return {
        diameter: 0.55, // numeric value in selected unit
        unit: 'mm', // 'mm' | 'um'
    };
}

function normalizeFieldOfViewSettings(input, defaults = defaultFieldOfViewSettings()) {
    const s = input && typeof input === 'object' ? input : {};
    const unit = s.unit === 'um' ? 'um' : 'mm';
    const diameter = fieldofview_settings_clampNumber(s.diameter ?? defaults.diameter, { min: 0.000001, max: 1e12, fallback: defaults.diameter });
    return { diameter, unit };
}

function loadFieldOfViewSettings() {
    const defaults = defaultFieldOfViewSettings();
    try {
        const raw = window.localStorage.getItem(fieldofview_settings_STORAGE_KEY);
        if (!raw) return defaults;
        return normalizeFieldOfViewSettings(JSON.parse(raw), defaults);
    } catch {
        return defaults;
    }
}

function saveFieldOfViewSettings(settings) {
    try {
        const normalized = normalizeFieldOfViewSettings(settings, defaultFieldOfViewSettings());
        window.localStorage.setItem(fieldofview_settings_STORAGE_KEY, JSON.stringify(normalized));
    } catch {
        // ignore storage errors
    }
}


